import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void cheaperDetourWins() {
        // Direct 0→1→3 = 10+15=25; detour 0→2→3 = 5+8=13
        int[][] fees = {{0,1,10},{1,3,15},{0,2,5},{2,3,8}};
        assertEquals(13L, new Solution().minTransferFee(4, fees, 0, 3));
    }

    @Test
    void srcEqualsDst_returnsZero() {
        int[][] fees = {{0,1,10}};
        assertEquals(0L, new Solution().minTransferFee(2, fees, 1, 1));
    }

    @Test
    void unreachable_returnsMinusOne() {
        // Only 0→1; cannot reach 2
        int[][] fees = {{0,1,5}};
        assertEquals(-1L, new Solution().minTransferFee(3, fees, 0, 2));
    }

    @Test
    void emptyFees_differentNodes_returnsMinusOne() {
        int[][] fees = {};
        assertEquals(-1L, new Solution().minTransferFee(4, fees, 0, 3));
    }

    @Test
    void directedOnly_noReturnRoute() {
        // Edge 0→1 exists; 1 cannot reach 0
        int[][] fees = {{0,1,20}};
        assertEquals(-1L, new Solution().minTransferFee(2, fees, 1, 0));
    }

    @Test
    void zeroFeeEdge() {
        // Some hops cost nothing (promotional routes)
        int[][] fees = {{0,1,0},{1,2,0},{2,3,100}};
        assertEquals(100L, new Solution().minTransferFee(4, fees, 0, 3));
    }

    @Test
    void multipleRoutesPicksMinimum() {
        // Paths 0→3: via 1 = 3+7=10; via 2 = 1+4=5; direct = 12
        int[][] fees = {{0,1,3},{0,2,1},{0,3,12},{1,3,7},{2,3,4}};
        assertEquals(5L, new Solution().minTransferFee(4, fees, 0, 3));
    }
}
